+        ReactCliRequest {
+            input_path: args.input.display().to_string(),
+            source_form: Some(args.source_form.as_str().to_string()),
+            runtime_mode: args.runtime_mode.map(|mode| mode.as_str().to_string()),
+            build_target: None,
+        },
+        row,
+        args.out.as_ref(),
+    );
+
