+        (ReactSourceForm::Jsx, Some(ReactRuntimeMode::Automatic)) => {
+            "jsx-automatic-runtime-compile"
+        }
+        (ReactSourceForm::Tsx, Some(ReactRuntimeMode::Automatic)) => {
